#include<bits/stdc++.h>
#define ll long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
CI MAXN=1e3+5;
int n,m,t,c,e[MAXN][MAXN],dis[MAXN],vis[MAXN],ans[MAXN],cnt;
signed main(void)
{
	n=read(),m=read(),t=read(),c=read();
	FOR(i,1,n)
	{
		FOR(j,1,n)
		{
			e[i][j]=(i!=j)*llinf;
		}
	}
	FOR(i,1,m)
	{
		int u=read(),v=read(),w=read();
		e[u][v]=min(e[u][v],w);
		e[v][u]=min(e[v][u],w);
	}
	FOR(i,1,n)
	{
		dis[i]=e[i][1];
	}
	vis[1]=1;
	FOR(i,1,n)
	{
		int mn=inf,u=1;
		FOR(j,1,n)
		{
			if(!vis[j]&&dis[j]<mn)
			{
				mn=dis[j],u=j;
			}
		}
		vis[u]=1;
		FOR(j,1,n)
		{
			if(!vis[j])
			{
				dis[j]=min(dis[j],dis[u]+e[u][j]);
			}
		}
	}
	cnt=0;
	FOR(i,1,t)
	{
		int x=read();
		if(dis[x]<=c)ans[++cnt]=i;
	}
	writeln(cnt);
	FOR(i,1,cnt)writeln(ans[i]);
	return false;
}
